  currentView: ViewState;
  onNavigate: (view: ViewState) => void;
  onLogout: () => void;
}

export const Layout: React.FC<LayoutProps> = ({ children, currentView, onNavigate, onLogout }) => {
  const navItems = [
    { id: 'dashboard', label: 'Dashboard', icon: LayoutGrid },
    { id: 'products', label: 'Products', icon: Package },
    { id: 'categories', label: 'Categories', icon: Database },
  ];

  return (
    <div className="flex h-screen bg-surface overflow-hidden">
      {/* Sidebar */}
      <div className="w-64 bg-sidebar border-r border-zinc-800 flex flex-col flex-shrink-0">
        <div className="p-6 flex items-center space-x-3">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-brand-600 to-brand-800 flex items-center justify-center text-white shadow-lg shadow-brand-900/20">
            <Box size={20} />
          </div>
          <span className="font-bold text-lg text-zinc-100 tracking-tight">StoreBase</span>
        </div>

        <nav className="flex-1 px-4 space-y-1 mt-6">
          {navItems.map((item) => {
            const Icon = item.icon;
            const isActive = currentView === item.id;
            return (
              <button
                key={item.id}
                onClick={() => onNavigate(item.id as ViewState)}
                className={`
                  w-full flex items-center space-x-3 px-3 py-2.5 rounded-md text-sm font-medium transition-all duration-200
                  ${isActive 
                    ? 'bg-brand-500/10 text-brand-400' 
                    : 'text-zinc-400 hover:text-zinc-100 hover:bg-zinc-800/50'
                  }
                `}
              >
                <Icon size={18} className={isActive ? 'text-brand-400' : 'text-zinc-500 group-hover:text-zinc-300'} />
                <span>{item.label}</span>
              </button>
            );
          })}
        </nav>

        <div className="p-4 border-t border-zinc-800 space-y-1">
          <button
            onClick={() => onNavigate('settings')}
            className={`
              w-full flex items-center space-x-3 px-3 py-2 rounded-md text-sm font-medium transition-colors
              ${currentView === 'settings' 
                ? 'bg-zinc-800 text-zinc-100' 
                : 'text-zinc-500 hover:text-zinc-300 hover:bg-zinc-800/30'
              }
            `}
          >
            <Settings size={18} />
            <span>Settings</span>
          </button>

          <button
            onClick={onLogout}
            className="w-full flex items-center space-x-3 px-3 py-2 rounded-md text-sm font-medium text-zinc-500 hover:text-red-400 hover:bg-red-500/5 transition-colors"
          >
            <LogOut size={18} />
            <span>Disconnect</span>
          </button>
        </div>
      </div>

      {/* Main Content */}
      <main className="flex-1 overflow-auto bg-surface relative">
        <div className="max-w-7xl mx-auto p-8">
          {children}
        </div>
      </main>
    </div>
  );
