import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Search, FolderOpen } from 'lucide-react';
import { Category } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';
import { Modal } from '../components/ui/Modal';
import { subscribeToCollection, addItem, deleteItem, CATEGORIES_COLLECTION } from '../services/firebase';

export const CategoriesPage: React.FC = () => {
  const [categories, setCategories] = useState<Category[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(false);

  // Form State
  const [formData, setFormData] = useState({ name: '', slug: '', description: '' });

  useEffect(() => {
    const unsubscribe = subscribeToCollection(CATEGORIES_COLLECTION, (data) => {
      setCategories(data as Category[]);
    });
    return () => unsubscribe();
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!formData.name) return;
    setLoading(true);
    try {
      await addItem(CATEGORIES_COLLECTION, formData);
      setIsModalOpen(false);
      setFormData({ name: '', slug: '', description: '' });
    } catch (error) {
      console.error(error);
      alert('Error creating category');
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (confirm('Are you sure? This action cannot be undone.')) {
      await deleteItem(CATEGORIES_COLLECTION, id);
    }
  };

  const filteredCategories = categories.filter(c => 
    c.name.toLowerCase().includes(search.toLowerCase()) || 
    c.slug.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Categories</h1>
          <p className="text-zinc-400 text-sm mt-1">Manage product categories for your store.</p>
        </div>
        <Button onClick={() => setIsModalOpen(true)}>
          <Plus size={16} className="mr-2" />
          Add Category
        </Button>
      </div>

      <div className="flex items-center gap-4 bg-zinc-900/50 p-1 rounded-lg border border-zinc-800 w-full max-w-md">
        <Search className="ml-3 text-zinc-500" size={18} />
        <input 
          type="text"
          placeholder="Search categories..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="bg-transparent border-none focus:ring-0 text-sm text-white w-full placeholder-zinc-500 h-9"
        />
      </div>

      {categories.length === 0 ? (
        <div className="text-center py-20 border border-dashed border-zinc-800 rounded-xl bg-zinc-900/20">
          <div className="mx-auto w-12 h-12 bg-zinc-800 rounded-full flex items-center justify-center text-zinc-400 mb-4">
            <FolderOpen size={24} />
          </div>
          <h3 className="text-white font-medium">No categories yet</h3>
          <p className="text-zinc-500 text-sm mt-1">Get started by creating your first category.</p>
        </div>
      ) : (
        <div className="bg-card border border-zinc-800 rounded-lg overflow-hidden shadow-sm">
          <div className="overflow-x-auto">
            <table className="w-full text-left text-sm">
              <thead className="bg-zinc-900/50 border-b border-zinc-800">
                <tr>
                  <th className="px-6 py-4 font-medium text-zinc-400">Name</th>
                  <th className="px-6 py-4 font-medium text-zinc-400">Slug</th>
                  <th className="px-6 py-4 font-medium text-zinc-400">Description</th>
                  <th className="px-6 py-4 text-right font-medium text-zinc-400">Actions</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-zinc-800">
                {filteredCategories.map((category) => (
                  <tr key={category.id} className="hover:bg-zinc-800/30 transition-colors group">
                    <td className="px-6 py-4 font-medium text-white">{category.name}</td>
                    <td className="px-6 py-4 text-zinc-400 font-mono text-xs bg-zinc-900/50 rounded px-2 py-1 inline-block mt-3">{category.slug}</td>
                    <td className="px-6 py-4 text-zinc-500 max-w-xs truncate">{category.description || '-'}</td>
                    <td className="px-6 py-4 text-right">
                      <button 
                        onClick={() => handleDelete(category.id)}
                        className="text-zinc-500 hover:text-red-400 transition-colors opacity-0 group-hover:opacity-100 p-1"
                      >
                        <Trash2 size={16} />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>
      )}

      <Modal isOpen={isModalOpen} onClose={() => setIsModalOpen(false)} title="New Category">
        <form onSubmit={handleSubmit} className="space-y-4">
          <Input 
            label="Name" 
            placeholder="e.g. Electronics"
            value={formData.name}
            onChange={(e) => setFormData({...formData, name: e.target.value})}
            required
            autoFocus
          />
          <Input 
            label="Slug" 
            placeholder="e.g. electronics"
            value={formData.slug}
            onChange={(e) => setFormData({...formData, slug: e.target.value})}
            required
          />
          <div>
            <label className="block text-xs font-medium text-zinc-400 mb-1.5 uppercase tracking-wider">
              Description
            </label>
            <textarea
              className="w-full bg-zinc-900 border border-zinc-800 rounded-md px-3 py-2 text-sm text-zinc-200 placeholder-zinc-600 focus:outline-none focus:ring-2 focus:ring-brand-500/50 focus:border-brand-500 min-h-[100px]"
              placeholder="Describe this category..."
              value={formData.description}
              onChange={(e) => setFormData({...formData, description: e.target.value})}
            />
          </div>
          <div className="flex justify-end pt-4">
            <Button type="button" variant="ghost" className="mr-2" onClick={() => setIsModalOpen(false)}>Cancel</Button>
            <Button type="submit" isLoading={loading}>Create Category</Button>
          </div>
        </form>
      </Modal>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { Plus, Trash2, Search, Upload, Image as ImageIcon, PackageOpen } from 'lucide-react';
import { Product, Category } from '../types';
import { Button } from '../components/ui/Button';
import { Input } from '../components/ui/Input';
import { Modal } from '../components/ui/Modal';
import { 
  subscribeToCollection, 
  addItem, 
  deleteItem, 
  uploadImage,
  PRODUCTS_COLLECTION, 
  CATEGORIES_COLLECTION 
} from '../services/firebase';

export const ProductsPage: React.FC = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [categories, setCategories] = useState<Category[]>([]);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [search, setSearch] = useState('');
  const [loading, setLoading] = useState(false);

  // Form
  const [name, setName] = useState('');
  const [categoryId, setCategoryId] = useState('');
  const [price, setPrice] = useState('');
  const [stock, setStock] = useState('');
  const [imageFile, setImageFile] = useState<File | null>(null);
  const [imagePreview, setImagePreview] = useState<string | null>(null);

  useEffect(() => {
    const unsubProd = subscribeToCollection(PRODUCTS_COLLECTION, (data) => setProducts(data as Product[]));
    const unsubCat = subscribeToCollection(CATEGORIES_COLLECTION, (data) => setCategories(data as Category[]));
    return () => {
      unsubProd();
      unsubCat();
    };
  }, []);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      const file = e.target.files[0];
      setImageFile(file);
      setImagePreview(URL.createObjectURL(file));
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!name || !categoryId || !price) return;

    setLoading(true);
    try {
      let imageUrl = '';
      if (imageFile) {
        imageUrl = await uploadImage(imageFile);
      } else {
        // Placeholder if no image provided? Or block?
        // Let's use a placeholder service
        imageUrl = `https://picsum.photos/seed/${encodeURIComponent(name)}/400/400`;
      }

      await addItem(PRODUCTS_COLLECTION, {
        name,
        categoryId,
        price: parseFloat(price),
        stock: parseInt(stock) || 0,
        imageUrl,
      });

      // Reset
      setIsModalOpen(false);
      setName('');
      setCategoryId('');
      setPrice('');
      setStock('');
      setImageFile(null);
      setImagePreview(null);
    } catch (error) {
      console.error(error);
      alert('Error creating product: ' + (error as Error).message);
    } finally {
      setLoading(false);
    }
  };

  const handleDelete = async (id: string) => {
    if (confirm('Delete this product?')) {
      await deleteItem(PRODUCTS_COLLECTION, id);
    }
  };

  const getCategoryName = (id: string) => categories.find(c => c.id === id)?.name || 'Unknown';

  const filteredProducts = products.filter(p => p.name.toLowerCase().includes(search.toLowerCase()));

  return (
    <div className="space-y-6">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white">Products</h1>
          <p className="text-zinc-400 text-sm mt-1">Manage your inventory and pricing.</p>
        </div>
        <Button onClick={() => setIsModalOpen(true)}>
          <Plus size={16} className="mr-2" />
          Add Product
        </Button>
      </div>

      <div className="flex items-center gap-4 bg-zinc-900/50 p-1 rounded-lg border border-zinc-800 w-full max-w-md">
        <Search className="ml-3 text-zinc-500" size={18} />
        <input 
          type="text"
          placeholder="Search products..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          className="bg-transparent border-none focus:ring-0 text-sm text-white w-full placeholder-zinc-500 h-9"
        />
      </div>

      {products.length === 0 ? (
         <div className="text-center py-20 border border-dashed border-zinc-800 rounded-xl bg-zinc-900/20">
         <div className="mx-auto w-12 h-12 bg-zinc-800 rounded-full flex items-center justify-center text-zinc-400 mb-4">
           <PackageOpen size={24} />
         </div>
         <h3 className="text-white font-medium">No products yet</h3>
         <p className="text-zinc-500 text-sm mt-1">Add items to your inventory.</p>
       </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
          {filteredProducts.map((product) => (
            <div key={product.id} className="group bg-card border border-zinc-800 rounded-xl overflow-hidden hover:border-brand-500/30 hover:shadow-xl hover:shadow-brand-900/10 transition-all duration-300 flex flex-col">
              <div className="relative aspect-square bg-zinc-900 overflow-hidden">
                {product.imageUrl ? (
                  <img src={product.imageUrl} alt={product.name} className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500" />
                ) : (
                  <div className="flex items-center justify-center h-full text-zinc-600">
                    <ImageIcon size={32} />
                  </div>
                )}
                <div className="absolute top-2 right-2 opacity-0 group-hover:opacity-100 transition-opacity">
                   <button 
                    onClick={() => handleDelete(product.id)}
                    className="p-2 bg-red-500/90 text-white rounded-md shadow-lg hover:bg-red-600 transition-colors"
                  >
                    <Trash2 size={16} />
                   </button>
                </div>
              </div>

              <div className="p-4 flex-1 flex flex-col">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-semibold text-white truncate pr-2" title={product.name}>{product.name}</h3>
                  <span className="text-brand-400 font-bold text-sm">${product.price.toFixed(2)}</span>
                </div>
                <div className="mb-4">
                  <span className="inline-flex items-center px-2 py-1 rounded text-xs font-medium bg-zinc-800 text-zinc-400">
                    {getCategoryName(product.categoryId)}
                  </span>
                </div>
                <div className="mt-auto flex items-center justify-between text-xs text-zinc-500 border-t border-zinc-800/50 pt-3">
                  <span>Stock: {product.stock}</span>
                  <span>Added {new Date(product.createdAt).toLocaleDateString()}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

