      )}

      {/* --- MODAL DE PRODUTO (Criar / Editar) --- */}
      <Modal 
        isOpen={isProductModalOpen} 
        onClose={() => setIsProductModalOpen(false)} 
        title={editingProduct ? "Editar Produto" : "Novo Produto"}
