export interface Category {
  id: string;
  name: string;
  description?: string;
  slug?: string;
  createdAt: number;
}

export interface Product {
  id: string;
  name: string;
  categoryId: string;
  imageUrl: string;
  price?: number;
  stock?: number;
  createdAt: number;
}

export interface FirebaseConfig {
  apiKey: string;
  authDomain: string;
  projectId: string;
  // storageBucket removido da obrigatoriedade pois usaremos ImgBB
  storageBucket?: string; 
  messagingSenderId: string;
  appId: string;
  measurementId?: string;
  imgbbApiKey?: string; // Nova chave para upload de imagens
}

import { initializeApp, FirebaseApp, getApps } from 'firebase/app';
import { getFirestore, Firestore, collection, addDoc, deleteDoc, updateDoc, doc, onSnapshot, query, orderBy } from 'firebase/firestore';
import { FirebaseConfig } from '../types';

// Configuração Padrão (Fallback)
const defaultFirebaseConfig: FirebaseConfig = {
  apiKey: "",
  authDomain: "",
  projectId: "",
  storageBucket: "",
  messagingSenderId: "",
  appId: "",
  imgbbApiKey: "" // Campo para a chave do ImgBB
};

const STORAGE_KEY = 'magikon_firebase_config';

// Singleton instances
let app: FirebaseApp | undefined;
let db: Firestore | undefined;

export const getStoredConfig = (): FirebaseConfig | null => {
  try {
    const stored = localStorage.getItem(STORAGE_KEY);
    return stored ? JSON.parse(stored) : null;
  } catch {
    return null;
  }
};

export const saveConfig = (config: FirebaseConfig) => {
  localStorage.setItem(STORAGE_KEY, JSON.stringify(config));
  window.location.reload();
};

export const clearConfig = () => {
  localStorage.removeItem(STORAGE_KEY);
  window.location.reload();
};

export const isInitialized = (): boolean => {
  return !!app;
};

export const initFirebase = (): boolean => {
  if (getApps().length > 0) {
    app = getApps()[0];
    db = getFirestore(app);
    return true;
  }

  const config = getStoredConfig();

  // Só inicializa se tiver configuração válida salva
  if (!config || !config.apiKey) {
    return false;
  }

  try {
    app = initializeApp(config);
    db = getFirestore(app);
    return true;
  } catch (error) {
    console.error("Erro na inicialização do Firebase:", error);
    return false;
  }
};

// Inicializa imediatamente
initFirebase();

// --- Métodos de Serviço ---

// Coleções
export const PRODUCTS_COLLECTION = 'products';
export const CATEGORIES_COLLECTION = 'categories';

export const subscribeToCollection = (collectionName: string, callback: (data: any[]) => void) => {
  if (!db) return () => {};
  const q = query(collection(db, collectionName), orderBy('createdAt', 'desc'));
  return onSnapshot(q, (snapshot) => {
    const items = snapshot.docs.map(doc => ({ id: doc.id, ...doc.data() }));
    callback(items);
  });
};

export const addItem = async (collectionName: string, data: any) => {
  if (!db) throw new Error("Banco de dados não inicializado. Configure o Firebase nas configurações.");
  await addDoc(collection(db, collectionName), {
    ...data,
    createdAt: Date.now()
  });
};

export const updateItem = async (collectionName: string, id: string, data: any) => {
  if (!db) throw new Error("Banco de dados não inicializado");
  const docRef = doc(db, collectionName, id);
  await updateDoc(docRef, {
    ...data,
    updatedAt: Date.now() 
  });
};

export const deleteItem = async (collectionName: string, id: string) => {
  if (!db) throw new Error("Banco de dados não inicializado");
  await deleteDoc(doc(db, collectionName, id));
};

/**
 * Faz upload da imagem para o ImgBB (Serviço Gratuito)
 * Requer uma chave de API configurada em Settings.
 */
export const uploadImage = async (file: File): Promise<string> => {
  const config = getStoredConfig();
  const apiKey = config?.imgbbApiKey;

  if (!apiKey) {
    throw new Error("Chave de API do ImgBB não configurada. Vá em Configurações para adicionar.");
  }

  const formData = new FormData();
  formData.append('image', file);

  try {
    const response = await fetch(`https://api.imgbb.com/1/upload?key=${apiKey}`, {
      method: 'POST',
      body: formData,
    });

    const data = await response.json();

    if (!data.success) {
      throw new Error(data.error?.message || 'Falha no upload da imagem');
    }

    // Retorna a URL de visualização direta
    return data.data.url;
  } catch (error) {
    console.error("Erro no upload ImgBB:", error);
    throw new Error("Falha ao conectar com ImgBB. Verifique sua chave de API.");
  }
};

