                  <p className="text-xs text-zinc-500 mt-1">PNG, JPG ou GIF</p>
                </div>
              )}
            </div>
          </div>

          <Input 
            label="Nome do Produto" 
            value={prodName}
            onChange={(e) => setProdName(e.target.value)}
