      if (prodImageFile) {
        imageUrl = await uploadImage(prodImageFile);
      } else if (!imageUrl) {
        // Placeholder
        imageUrl = `https://picsum.photos/seed/${encodeURIComponent(prodName)}/400/400`;
      }

      const productData = {
        name: prodName,
        categoryId: prodCategoryId,
