      };

      if (editingProduct) {
        await updateItem(PRODUCTS_COLLECTION, editingProduct.id, productData);
      } else {
        await addItem(PRODUCTS_COLLECTION, productData);
      }

      setIsProductModalOpen(false);
    } catch (error) {
      console.error(error);
      alert('Erro ao salvar produto: ' + (error as Error).message);
    } finally {
      setLoading(false);
    }
